sql:
SELECT AVG(time_spent_minutes) AS avg_time_spent
FROM online_classes
WHERE class_name = 'Introduction to Programming';

SELECT student_id, COUNT(*) AS number_of_online_classes
FROM online_classes
GROUP BY student_id;

SELECT subject, AVG(time_spent_minutes) AS avg_time_spent
FROM self_study
GROUP BY subject;

external_knowledge:
- 'shining beacons' refers to the most active students; 
- 'light has illuminated their pursuit of knowledge for at least an hour' means the students have spent at least 60 minutes on activities; 
- 'torches alight in both online and self-led exploration' indicates the activities include both online classes and self-study.

sql:
SELECT student_name
FROM students
ORDER BY age DESC;

SELECT 
    (SELECT SUM(time_spent_minutes) FROM online_classes) AS total_online_class_time,
    (SELECT SUM(time_spent_minutes) FROM self_study) AS total_self_study_time;
